
.dashboard {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

// ═══ 通用卡片 ═══
.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);

  h2 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 15px;
    font-weight: 600;
    color: var(--color-text-primary);

    i {
      color: var(--color-gold);
    }
  }
}

.card-body {
  padding: var(--spacing-lg);
}

// ═══ 时空舆情卡 ═══
.climate-badge {
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 600;
  border-radius: var(--radius-full);
  background: var(--color-bg-elevated);
  color: var(--color-text-secondary);

  &.gold {
    background: rgba(216, 166, 87, 0.2);
    color: var(--color-gold);
  }
  &.danger {
    background: rgba(255, 107, 107, 0.2);
    color: var(--color-danger);
  }
  &.warning {
    background: rgba(224, 195, 108, 0.2);
    color: var(--color-warning);
  }
}

.info-grid {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.info-item {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .value {
    font-size: 13px;
    color: var(--color-text-secondary);
    line-height: 1.5;

    &.highlight {
      color: var(--color-gold);
    }
    &.warning {
      color: var(--color-warning);
    }
  }
}

// ═══ 场景卡 ═══
.scene-type {
  padding: 4px 10px;
  font-size: 11px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

.scene-desc {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-md);
}

.scene-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  margin-bottom: var(--spacing-md);

  .mood {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    color: var(--color-text-muted);

    i {
      color: var(--color-romance-light);
    }
  }
}

.present-chars {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  flex-wrap: wrap;

  i {
    color: var(--color-text-muted);
    font-size: 12px;
  }
}

.char-tag {
  padding: 2px 8px;
  font-size: 11px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
}

.topic {
  padding: var(--spacing-sm) var(--spacing-md);
  background: rgba(216, 166, 87, 0.1);
  border-radius: var(--radius-md);
  font-size: 12px;
  color: var(--color-gold);

  i {
    margin-right: 6px;
  }
}

// ═══ 统计卡片行 ═══
.stat-row {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-md);

  @media (min-width: 600px) {
    grid-template-columns: repeat(4, 1fr);
  }
}

.stat-card {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-lg);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    transform: translateY(-2px);
  }

  .stat-icon {
    width: 44px;
    height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-bg-elevated);
    border-radius: var(--radius-md);
    font-size: 18px;
    color: var(--color-gold);
  }

  &.romance .stat-icon {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }
  &.danger .stat-icon {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.success .stat-icon {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }

  .stat-info {
    display: flex;
    flex-direction: column;
  }

  .stat-value {
    font-size: 22px;
    font-weight: 700;
    color: var(--color-text-primary);
    font-family: var(--font-display);
  }

  .stat-label {
    font-size: 12px;
    color: var(--color-text-muted);
  }
}

// ═══ 待办事项 ═══
.count-badge {
  padding: 2px 8px;
  font-size: 11px;
  font-weight: 600;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
}

.todo-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.todo-item {
  padding: var(--spacing-md);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  border-left: 3px solid var(--color-border);

  &.urgent {
    border-left-color: var(--color-danger);
  }
  &.high {
    border-left-color: var(--color-warning);
  }
  &.normal {
    border-left-color: var(--color-info);
  }
}

.todo-main {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-xs);
}

.todo-urgency {
  padding: 2px 6px;
  font-size: 10px;
  font-weight: 600;
  background: var(--color-bg-card);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);

  .urgent & {
    color: var(--color-danger);
  }
  .high & {
    color: var(--color-warning);
  }
}

.todo-text {
  font-size: 13px;
  color: var(--color-text-primary);
}

.todo-meta {
  display: flex;
  gap: var(--spacing-md);
  font-size: 11px;
  color: var(--color-text-muted);

  i {
    margin-right: 4px;
  }
}

// ═══ 关系索引 ═══
.more-link {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: var(--color-text-muted);

  &:hover {
    color: var(--color-gold);
  }
}

.relation-grid {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.relation-item {
  display: flex;
  flex-direction: column;
  gap: 6px;

  .rel-label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .rel-value {
    font-size: 14px;
    color: var(--color-text-primary);

    &.gold {
      color: var(--color-gold);
    }
  }
}

.rel-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
}

.rel-tag {
  padding: 3px 10px;
  font-size: 12px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);

  &.gold {
    background: rgba(216, 166, 87, 0.15);
    color: var(--color-gold);
  }
  &.romance {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }
  &.warning {
    background: rgba(224, 195, 108, 0.15);
    color: var(--color-warning);
  }
  &.danger {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
}
