
.characters-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

// ═══ 工具栏 ═══
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-md);
  align-items: center;
}

.search-box {
  flex: 1;
  min-width: 200px;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);

  i {
    color: var(--color-text-muted);
  }

  input {
    flex: 1;
    background: transparent;
    color: var(--color-text-primary);

    &::placeholder {
      color: var(--color-text-muted);
    }
  }
}

.filter-select {
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text-primary);
}

.add-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-lg);
  background: var(--color-gold);
  color: var(--color-bg-dark);
  border-radius: var(--radius-md);
  font-weight: 600;
  font-size: 13px;

  &:hover {
    filter: brightness(1.1);
  }
}

// ═══ 人物列表 ═══
.char-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: var(--spacing-md);
}

.char-card {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    background: var(--color-bg-elevated);
    border-color: var(--color-border-light);
  }

  &.selected {
    border-color: var(--color-gold);
    box-shadow: var(--shadow-glow-gold);
  }
}

.char-avatar {
  width: 56px;
  height: 56px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  color: var(--color-text-muted);
  font-size: 22px;
}

.char-info {
  flex: 1;
  min-width: 0;
}

.char-name {
  font-size: 15px;
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: 2px;
}

.char-meta {
  font-size: 12px;
  color: var(--color-text-secondary);
  margin-bottom: 6px;
}

.char-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.tag {
  padding: 2px 6px;
  font-size: 10px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);

  &.gold {
    background: rgba(216, 166, 87, 0.15);
    color: var(--color-gold);
  }
  &.romance {
    background: rgba(255, 77, 109, 0.15);
    color: var(--color-romance-light);
  }
  &.danger {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.success {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }
  &.info {
    background: rgba(122, 162, 247, 0.15);
    color: var(--color-info);
  }
}

.char-stats {
  display: flex;
  flex-direction: column;
  gap: 6px;
  width: 80px;
}

.stat-bar {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;

  i {
    color: var(--color-text-muted);
    width: 12px;
  }

  .bar {
    flex: 1;
    height: 4px;
    background: var(--color-bg-elevated);
    border-radius: 2px;
    overflow: hidden;
  }

  .fill {
    height: 100%;
    border-radius: 2px;
    transition: width 0.3s;

    &.high {
      background: var(--color-success);
    }
    &.mid {
      background: var(--color-warning);
    }
    &.low {
      background: var(--color-danger);
    }
  }

  span {
    width: 20px;
    text-align: right;
    color: var(--color-text-muted);
  }
}

.empty-state {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-2xl);
  color: var(--color-text-muted);

  i {
    font-size: 48px;
  }
}

// ═══ 抽屉 ═══
.drawer-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-slow);
  z-index: var(--z-drawer);

  &.open {
    opacity: 1;
    visibility: visible;
  }
}

.drawer {
  position: fixed;
  top: 0;
  right: 0;
  width: 420px;
  max-width: 90vw;
  height: 100%;
  background: var(--color-bg-card);
  border-left: 1px solid var(--color-border);
  transform: translateX(100%);
  transition: transform var(--transition-slow);
  z-index: calc(var(--z-drawer) + 1);
  display: flex;
  flex-direction: column;

  &.open {
    transform: translateX(0);
  }
}

.drawer-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);
  background: linear-gradient(135deg, rgba(216, 166, 87, 0.1) 0%, transparent 100%);
}

.drawer-avatar {
  position: relative;
  width: 64px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-lg);
  color: var(--color-text-muted);
  font-size: 28px;

  .upload-btn {
    position: absolute;
    bottom: -4px;
    right: -4px;
    width: 24px;
    height: 24px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--color-gold);
    border-radius: 50%;
    color: var(--color-bg-dark);
    font-size: 10px;
    cursor: pointer;
    opacity: 0;
    transition: opacity var(--transition-fast);
  }

  &:hover .upload-btn {
    opacity: 1;
  }
}

.drawer-title {
  flex: 1;

  h3 {
    font-size: 18px;
    font-weight: 600;
    color: var(--color-text-primary);
  }

  .subtitle {
    font-size: 13px;
    color: var(--color-gold);
  }
}

.drawer-close {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-secondary);

  &:hover {
    color: var(--color-text-primary);
  }
}

.drawer-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
}

.detail-section {
  margin-bottom: var(--spacing-xl);

  h4 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 14px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin-bottom: var(--spacing-md);
    padding-bottom: var(--spacing-sm);
    border-bottom: 1px solid var(--color-border);

    i {
      color: var(--color-gold);
    }
  }

  &.romance h4 i {
    color: var(--color-romance-light);
  }
}

.info-grid,
.relation-detail,
.romance-detail {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--spacing-sm) var(--spacing-md);
}

.info-row {
  display: flex;
  flex-direction: column;
  gap: 2px;

  &.full {
    grid-column: 1 / -1;
  }

  .label {
    font-size: 11px;
    color: var(--color-text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  .value {
    font-size: 13px;
    color: var(--color-text-secondary);

    &.romance {
      color: var(--color-romance-light);
    }
    &.danger {
      color: var(--color-danger);
    }
    &.warning {
      color: var(--color-warning);
    }
  }
}

.stats-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

.stat-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .stat-label {
    width: 60px;
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .stat-bar-lg {
    flex: 1;
    height: 8px;
    background: var(--color-bg-elevated);
    border-radius: 4px;
    overflow: hidden;

    .fill {
      height: 100%;
      border-radius: 4px;
      transition: width 0.3s;

      &.high {
        background: linear-gradient(90deg, var(--color-success), #6dd5a0);
      }
      &.mid {
        background: linear-gradient(90deg, var(--color-warning), #f0d78c);
      }
      &.low {
        background: linear-gradient(90deg, var(--color-danger), #ff9999);
      }
    }
  }

  .stat-num {
    width: 30px;
    text-align: right;
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
  }
}

.danger-bar {
  flex: 1;
  height: 6px;
  background: var(--color-bg-elevated);
  border-radius: 3px;
  overflow: hidden;

  .fill {
    height: 100%;
    background: var(--color-romance-gradient);
    border-radius: 3px;
  }
}

.danger-num {
  font-size: 12px;
  color: var(--color-romance-light);
  font-weight: 600;
}

.status-text {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
}

.drawer-actions {
  display: flex;
  gap: var(--spacing-md);
  margin-top: var(--spacing-lg);
  padding-top: var(--spacing-lg);
  border-top: 1px solid var(--color-border);
}

.action-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;

  &.edit {
    background: var(--color-gold);
    color: var(--color-bg-dark);
  }

  &.delete {
    background: transparent;
    border: 1px solid var(--color-danger);
    color: var(--color-danger);

    &:hover {
      background: rgba(255, 107, 107, 0.1);
    }
  }
}
