
.romance-page {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

// ═══ 工具栏 ═══
.toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--spacing-md);
}

.search-box {
  flex: 1;
  max-width: 300px;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);

  i {
    color: var(--color-text-muted);
  }

  input {
    flex: 1;
    color: var(--color-text-primary);

    &::placeholder {
      color: var(--color-text-muted);
    }
  }
}

.stats {
  .count {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 13px;
    color: var(--color-romance-light);

    i {
      color: var(--color-romance);
    }
  }
}

// ═══ 卡片网格 ═══
.romance-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: var(--spacing-lg);
}

.romance-card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  cursor: pointer;
  transition: all var(--transition-fast);

  &:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-glow-romance);
    border-color: var(--color-romance);
  }

  &.selected {
    border-color: var(--color-romance);
    box-shadow: var(--shadow-glow-romance);
  }
}

.card-cover {
  position: relative;
  height: 120px;
  background: linear-gradient(135deg, rgba(196, 30, 58, 0.3) 0%, rgba(255, 77, 109, 0.1) 100%);
  background-size: cover;
  background-position: center;

  .cover-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, transparent 50%, var(--color-bg-card) 100%);
  }
}

.upload-cover {
  position: absolute;
  top: var(--spacing-sm);
  right: var(--spacing-sm);
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.5);
  border-radius: var(--radius-sm);
  color: white;
  font-size: 12px;
  cursor: pointer;
  opacity: 0;
  transition: opacity var(--transition-fast);

  .romance-card:hover & {
    opacity: 1;
  }
}

.danger-indicator {
  position: absolute;
  bottom: var(--spacing-sm);
  left: var(--spacing-sm);
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 8px;
  background: rgba(0, 0, 0, 0.6);
  border-radius: var(--radius-sm);
  font-size: 11px;
  color: white;

  &.critical {
    background: rgba(255, 77, 109, 0.9);
  }
  &.high {
    background: rgba(255, 107, 107, 0.8);
  }
  &.medium {
    background: rgba(224, 195, 108, 0.8);
    color: var(--color-bg-dark);
  }
}

.card-content {
  padding: var(--spacing-md);
}

.char-name {
  font-size: 16px;
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: 2px;
}

.char-position {
  font-size: 12px;
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);
}

.stage-progress {
  margin-bottom: var(--spacing-sm);

  .stage-label {
    font-size: 11px;
    color: var(--color-romance-light);
  }

  .stage-bar {
    height: 4px;
    background: var(--color-bg-elevated);
    border-radius: 2px;
    margin-top: 4px;
    overflow: hidden;

    .stage-fill {
      height: 100%;
      background: var(--color-romance-gradient);
      border-radius: 2px;
    }
  }
}

.emotion-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  font-size: 11px;
  background: var(--color-bg-elevated);
  border-radius: var(--radius-full);
  color: var(--color-text-secondary);
  margin-bottom: var(--spacing-sm);

  &.positive {
    background: rgba(74, 193, 142, 0.15);
    color: var(--color-success);
  }
  &.negative {
    background: rgba(255, 107, 107, 0.15);
    color: var(--color-danger);
  }
  &.warning {
    background: rgba(224, 195, 108, 0.15);
    color: var(--color-warning);
  }
}

.identity-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-bottom: var(--spacing-sm);
}

.id-tag {
  padding: 2px 6px;
  font-size: 10px;
  background: rgba(255, 77, 109, 0.1);
  border-radius: var(--radius-sm);
  color: var(--color-romance-light);
}

.recent-event {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  font-size: 12px;
  color: var(--color-text-muted);

  i {
    margin-top: 2px;
    color: var(--color-text-muted);
  }
}

.empty-state {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-md);
  padding: var(--spacing-2xl);
  color: var(--color-text-muted);

  i {
    font-size: 48px;
    color: var(--color-romance);
    opacity: 0.5;
  }
}

// ═══ 抽屉 ═══
.drawer-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-slow);
  z-index: var(--z-drawer);

  &.open {
    opacity: 1;
    visibility: visible;
  }
}

.romance-drawer {
  position: fixed;
  top: 0;
  right: 0;
  width: 420px;
  max-width: 90vw;
  height: 100%;
  background: var(--color-bg-card);
  border-left: 1px solid var(--color-border);
  transform: translateX(100%);
  transition: transform var(--transition-slow);
  z-index: calc(var(--z-drawer) + 1);
  display: flex;
  flex-direction: column;

  &.open {
    transform: translateX(0);
  }
}

.drawer-header {
  position: relative;
  min-height: 160px;
}

.drawer-cover {
  position: absolute;
  inset: 0;
  background: var(--color-romance-gradient);
  background-size: cover;
  background-position: center;

  .cover-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, transparent 30%, var(--color-bg-card) 100%);
  }
}

.drawer-title-area {
  position: absolute;
  bottom: var(--spacing-md);
  left: var(--spacing-lg);

  h3 {
    font-size: 22px;
    font-weight: 700;
    color: white;
    text-shadow: 0 2px 8px rgba(0, 0, 0, 0.5);
  }

  .subtitle {
    font-size: 13px;
    color: rgba(255, 255, 255, 0.8);
  }
}

.drawer-close {
  position: absolute;
  top: var(--spacing-md);
  right: var(--spacing-md);
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.4);
  border-radius: var(--radius-sm);
  color: white;

  &:hover {
    background: rgba(0, 0, 0, 0.6);
  }
}

.drawer-body {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
}

.status-card {
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  padding: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

.status-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-xs) 0;

  .status-label {
    font-size: 12px;
    color: var(--color-text-muted);
  }

  .status-value {
    font-size: 13px;
    color: var(--color-text-secondary);

    &.highlight {
      color: var(--color-romance-light);
      font-weight: 600;
    }
    &.positive {
      color: var(--color-success);
    }
    &.negative {
      color: var(--color-danger);
    }
    &.warning {
      color: var(--color-warning);
    }
  }
}

.danger-meter {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-sm);
  padding-top: var(--spacing-sm);
  border-top: 1px solid var(--color-border);

  .danger-label {
    font-size: 12px;
    color: var(--color-text-muted);
    width: 50px;
  }

  .danger-bar {
    flex: 1;
    height: 8px;
    background: var(--color-bg-card);
    border-radius: 4px;
    overflow: hidden;

    .danger-fill {
      height: 100%;
      background: var(--color-romance-gradient);
      border-radius: 4px;
    }
  }

  .danger-value {
    width: 40px;
    text-align: right;
    font-size: 13px;
    font-weight: 600;
    color: var(--color-romance-light);
  }
}

.detail-section {
  margin-bottom: var(--spacing-lg);

  h4 {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: 13px;
    font-weight: 600;
    color: var(--color-text-primary);
    margin-bottom: var(--spacing-sm);

    i {
      color: var(--color-romance-light);
    }
  }

  &.sensitive h4 i {
    color: var(--color-warning);
  }
}

.desc-text {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text-secondary);
}

.grip-info {
  background: var(--color-bg-elevated);
  border-radius: var(--radius-md);
  padding: var(--spacing-md);

  &.masked {
    filter: blur(6px);
    user-select: none;
  }
}

.grip-row {
  margin-bottom: var(--spacing-sm);

  &:last-child {
    margin-bottom: 0;
  }

  .grip-label {
    font-size: 11px;
    color: var(--color-text-muted);
    display: block;
    margin-bottom: 2px;
  }

  .grip-value {
    font-size: 13px;
    color: var(--color-text-secondary);

    &.danger {
      color: var(--color-danger);
    }
  }
}

.unmask-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: var(--spacing-sm);
  padding: 4px 10px;
  font-size: 12px;
  color: var(--color-text-muted);
  background: var(--color-bg-elevated);
  border-radius: var(--radius-sm);

  &:hover {
    color: var(--color-text-primary);
  }
}

.contact-info {
  display: flex;
  flex-direction: column;
  gap: 4px;

  .contact-type {
    font-size: 12px;
    color: var(--color-romance-light);
  }

  .contact-detail {
    font-size: 13px;
    color: var(--color-text-secondary);
  }
}
